INSERT INTO `content` (`id`, `slug`, `content`) VALUES
(1, 'index1', 'Основні статистичні показники життя міста'),
(3, 'index2', 'Показники оцінювання якості життя мешканцями міста'),
(4, 'index3', 'Показники ефективності виконання Комплексної стратегії розвитку Львова до 2025 року\r\n'),
(5, 'about1', '<p>Проект «Панель міста» - це відкрита платформа із показниками з різних сфер життя міста.\n\nМетою проекту є створення можливості безперешкодного доступу громадськості до основних показників розвитку міста у зручному форматі.</p><p><br></p>\n\n\n'),
(6, 'about2', 'Загалом на порталі «Панель міста» можна ознайомитись з даними, які описують такі сфери як населення, бюджет міста, показники економічного розвитку міста, благоустрій, комунальні послуги, транспорт, освіта, охорона здоров’я, безпека, культура, адміністративні послуги тощо, а також переглянути дані в динаміці з 2010 року.'),
(7, 'about3', '<p>Проект розроблений спільно ЛКП \"Міський центр інформаційних технологій\" Львівської міської ради, Комунальною установою Інститут міста у співпраці з компаніями <a target=\"_blank\" href=\"http://sigma.software/\">Sigma Software</a> та\n					   <a target=\"_blank\" href=\"http://eucalipse.com\">Eucalipse</a> в рамках Програми цифрового перетворення Львова до 2020 року.</p>'),
(8, 'about4', 'Портал «Панель міста» об’єднує понад 800 показників, які структуровані у 3 змістовні блоки:'),
(9, 'about5', 'У цьому розділі Ви можете ознайомитись із основними статистичними показниками від різних підрозділів Львівської міської ради, а також інших установ, що описують стан справ в різних сферах життя міста. Показники актуальні станом на 2016 рік.'),
(10, 'about6', 'Показники у цьому розділі відображають суб’єктивні оцінки мешканців щодо якості життя у місті. Показники розраховані згідно з методологією дослідження якості життя у місті, розробленою Інститутом міста та Соціологічною агенцією \"Фама\". Детальніше з методологією можна ознайомитись за <a href=\"http://www.city-institute.org/index.php/uk/doslidzhennia/35-quality-of-life\">посиланням</a>.'),
(11, 'about7', 'Тут Ви можете переглянути показники ефективності виконання Комплексної стратегії розвитку Львова до 2025 року. Детальніше з стратегією можна ознайомитись за 											<a href=\"http://www.city-institute.org/index.php/uk/stratehii/27-complex-strategy\">посиланням</a>.'),
(12, 'footer', '<p>© 2016-2020. Всі права захищено. Всі права на статті, ілюстрації, інші матеріали належать ЛМР та ЛКП “Міський центр інформаційних технологій” та охороняються Законом України «Про авторське право і суміжні права». При використанні матеріалів посилання на сайт обов\'язкове! Весь контент доступний за ліцензією <a href=\"https://creativecommons.org/licenses/by/4.0/\" style=\"\">Creative Commons Attribution 4.0 International license</a>, якщо не вказано інше.</p>');
