(1, 239, '1.1.1.1.1', '1.1.1.1', 'Чисельність наявного населення на кінець звітного року (на 1 січня наступного за звітним року)', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Чисельність наявного населення міста Львова (включаючи м. Винники, смт Рудне та смт Брюховичі) на кінець звітного року (на 1 січня наступного за звітним роком), в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', 750, 770, 5),
(2, 239, '1.1.1.1.2', '1.1.1.1', 'Чисельність постійного населення на кінець звітного року', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Чисельність постійного населення міста Львова на кінець звітного року в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(3, 239, '1.1.1.1.3', '1.1.1.1', 'Площа територіальної громади (міста)', 'Головне управління статистики у Львівській області', 3, 'кв.км', '<p>Площа територіальної громади (міста) Львова в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(4, 239, '1.1.1.1.4', '1.1.1.1', 'Густота населення ', 'Розрахунковий показник', 35, 'тис. осіб/кв.км', '<p>Густота населення міста Львова динаміці із 2010 року (Чисельність постійного населення на кінець звітного року / Площа територіальної громади (міста)<br></p>', 0, '1', '<p><br></p>', 1, '{1.1.1.1.2}/{1.1.1.1.3}', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(5, 240, '1.1.1.2.1', '1.1.1.2', 'Кількість чоловіків ', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість осіб чоловічої статі у місті Львові у динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(6, 240, '1.1.1.2.2', '1.1.1.2', 'Кількість жінок ', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Частка осіб жіночої статі у місті Львові у динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(7, 240, '1.1.1.2.3', '1.1.1.2', 'Кількість чоловіків на 100 жінок ', 'Розрахунковий показник', 35, 'осіб', '<p>Співвідношення кількості осіб чоловічої статі із кількістю осіб жіночої статі у Львові в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 1, '{1.1.1.2.1}/{1.1.1.2.2}*100', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(8, 241, '1.1.1.3.1', '1.1.1.3', 'Кількість населення у віці 0-15 років', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість населення, у віці від 0 до 15 років включно у місті Львів в динаміці із 2010 року.<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(9, 241, '1.1.1.3.2', '1.1.1.3', 'Кількість населення від 0 до 6 років включно', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість населення міста Львова, віком від 0 до 6 років включно в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
(10, 241, '1.1.1.3.3', '1.1.1.3', 'Кількість населення віком від 7 до 15 років включно', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість населення міста Львова, віком від 7 до 15 років включно в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '8c57f5f4-8c6a-4a74-bb8d-2e7b8aa1ae3e', 'd11ad6b0-4bbb-44cb-862c-86ed67b7c220', NULL, NULL, NULL),
