(757, 359, '1.15.1.2.7', '1.15.1.2', 'Запис на особистий прийом до керівників районних адміністрацій', 'Департамент адміністративних послуг Львівської міської ради', 23, 'одиниць', '<p><br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '36b1dbe6-e15b-4380-873b-05ab302fa271', '3a9d75be-815e-4d5e-ba1d-b7ddf5704ecd', NULL, NULL, NULL),
(760, 279, '1.3.1.1.20', '1.3.1.1', 'Надходження прямих іноземних інвестицій ', 'Головне управління статистики у Львівській області', 3, 'млн дол.', '<p><span style=\"color: rgb(51, 51, 51); font-family: proxima_nova_regular, Arial, sans-serif; font-size: 14px;\">Обсяг прямих іноземних інвестицій, що надійшли протягом року суб\'єктам підприємницької діяльності з іноземним капіталом у Львові в динаміці з 2010 року.&nbsp;</span><span style=\"font-family: Roboto, RobotoDraft, Helvetica, Arial, sans-serif; white-space: pre-wrap;\"><span style=\"font-weight: 700;\">Оновлення цього показника тимчасово припинено</span> у зв</span>\'язку із наступним: складання статистики прямих інвестицій в розрізі міст та районів обласного значення Національним банком України не передбачено, оскільки публікація таких даних була припинена територіальними органами Державної служби статистики ще з початку 2019 року (згідно з планом державних статистичних спостережень на 2019 рік, затвердженим розпорядженням Кабінету Міністрів України від 10 квітня 2019 року № 283-р).<br></p>', 0, '1', '<p><br></p>', 0, 'NONE', 1, '17d9705c-faa9-4893-90fb-f8699c10e257', '4db9e491-130e-47d4-92b7-71ffd3038d5b', 0, 0, 0),
(761, 279, '1.3.1.1.21', '1.3.1.1', 'Кількість малих підприємств - суб\'єктів підприємницької діяльності', 'Головне управління статистики у Львівській області', 3, 'одиниць', '<p>Загальна кількість малих підприємств (чисельність штату яких не перевищує 50 осіб та річний дохід від будь-якої діяльності не перевищує суми, еквівалетної 10 млн євро, визначену середньорічним курсом Національного банку України), зареєстрованих у Львові в динаміці з 2012 року.</p>', 0, '1', '<p><br></p>', 0, 'NONE', 0, '17d9705c-faa9-4893-90fb-f8699c10e257', '4db9e491-130e-47d4-92b7-71ffd3038d5b', NULL, NULL, NULL),
