(1, 239, '1.1.1.1.1', '1.1.1.1', 'Кількість наявного населення на кінець року', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Чисельність наявного населення міста Львова (включаючи м. Винники, смт Рудне та смт Брюховичі) на кінець звітного року (на 1 січня наступного за звітним роком), в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(2, 239, '1.1.1.1.2', '1.1.1.1', 'Кількість постійного населення на кінець звітного року', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Чисельність постійного населення міста Львова на кінець звітного року в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(3, 239, '1.1.1.1.3', '1.1.1.1', 'Територія', 'Головне управління статистики у Львівській області', 3, 'кв. км', '<p>Площа територіальної громади (міста) Львова в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
