(7, 240, '1.1.1.2.3', '1.1.1.2', 'Кількість чоловіків на 100 жінок ', 'Розрахунковий показник', 35, 'осіб', '<p>Співвідношення кількості осіб чоловічої статі із кількістю осіб жіночої статі у Львові в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 1, '{1.1.1.2.1}/{1.1.1.2.2}*100', 0, NULL, NULL, 0, 0, 0),
(8, 241, '1.1.1.3.1', '1.1.1.3', 'Кількість населення у віці 0-15 років', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість населення, у віці від 0 до 15 років включно у місті Львів в динаміці із 2010 року.<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
