(15, 241, '1.1.1.3.8', '1.1.1.3', 'Кількість чоловіків у віці 60 років і старше', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість осіб чоловічої статі, у віці 60 років і старше у місті Львові в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(16, 241, '1.1.1.3.9', '1.1.1.3', 'Кількість жінок у віці 60 років і старше', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість осіб жіночої статі, у віці 60 років і старше у місті Львові в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(17, 241, '1.1.1.3.10', '1.1.1.3', 'Населення молодше від працездатного віку у % до всього населення ', 'Розрахунковий показник', 35, '%', '<p>Частка населення, молодшого від працездатного віку (особи, віком до 15 років включно) у місті Львів в динаміці із 2010 року.<br></p>', 1, '1', '<p><br></p>', 1, '{1.1.1.3.1}/{1.1.1.1.2}*100', 0, NULL, NULL, 0, 0, 0),
(18, 241, '1.1.1.3.11', '1.1.1.3', 'Населення працездатного віку у % до всього населення ', 'Розрахунковий показник', 35, '%', '<p>Частка населення працездатного віку (чоловіки, віком від 16 до 64 років включно та жінки, віком від 16 до 59 років включно) у місті Львові в динаміці із 2010<br></p>', 1, '1', '<p><br></p>', 1, '{1.1.1.3.4}/{1.1.1.1.2}*100', 0, NULL, NULL, 0, 0, 0),
(19, 241, '1.1.1.3.12', '1.1.1.3', 'Населення старше від працездатного віку у % до всього населення ', 'Розрахунковий показник', 35, '%', '<p>Частка населення, старшого від працездатного віку (особи, старші 60 років) у місті Львів в динаміці із 2010 р.<br></p>', 1, '1', '<p><br></p>', 1, '{1.1.1.3.7}/{1.1.1.1.2}*100', 0, NULL, NULL, 0, 0, 0),
(20, 242, '1.1.1.4.1', '1.1.1.4', 'Кількість пенсіонерів на кінець року', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість осіб, які отримують пенсію (регулярну грошову допомогу, що виплачується особам, які досягли пенсійного віку, стали інвалідами або втратили годувальника) у місті Львові в динаміці із 2010<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(21, 242, '1.1.1.4.2', '1.1.1.4', 'Кількість народжених ', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість народжених осіб у місті Львові за звітний рік в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(22, 242, '1.1.1.4.3', '1.1.1.4', 'Кількість померлих ', 'Головне управління статистики у Львівській області', 3, 'тис. осіб', '<p>Кількість померлих осіб у місті Львові за звітний рік в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(23, 242, '1.1.1.4.4', '1.1.1.4', 'Кількість пенсіонерів на 1000 мешканців', 'Розрахунковий показник', 35, 'осіб', '<p>Співвідношення кількості осіб, які отримують пенсію, із загальною кількістю населення міста Львів, в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 1, '{1.1.1.4.1}/{1.1.1.1.2}*100', 0, NULL, NULL, 0, 0, 0),
(24, 242, '1.1.1.4.5', '1.1.1.4', 'Кількість народжених на 1000 мешканців', 'Розрахунковий показник', 35, 'осіб', '<p>Співвідношення кількості народжених осіб із загальною кількістю населення міста Львів, в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 1, '{1.1.1.4.2}/{1.1.1.1.2}*100', 0, NULL, NULL, 0, 0, 0),
(25, 242, '1.1.1.4.6', '1.1.1.4', 'Кількість померлих на 1000 мешканців', 'Розрахунковий показник', 35, 'осіб', '<p>Співвідношення кількості померлих осіб до загальної кількості населення міста Львів, в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 1, '{1.1.1.4.3}/{1.1.1.1.2}*100', 0, NULL, NULL, 0, 0, 0),
(26, 242, '1.1.1.4.7', '1.1.1.4', 'Загальний приріст (скорочення) населення', 'Головне управління статистики у Львівській області', 3, 'осіб', '<p>Приріст / зменшення наявного населення міста Львова у порівнянні із попереднім роком, в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(27, 242, '1.1.1.4.8', '1.1.1.4', 'Природний приріст (скорочення) населення', 'Головне управління статистики у Львівській області', 3, 'осіб', '<p>Природний приріст / зменшення постійного населення міста Львів в динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
(28, 242, '1.1.1.4.9', '1.1.1.4', 'Кількість осіб, що прибули у місто (імміграція)', 'Головне управління статистики у Львівській області', 3, 'осіб', '<p>Кількість осіб, які прибули до міста Львів, у динаміці із 2010 року<br></p>', 0, '1', '<p><br></p>', 0, '', 0, NULL, NULL, 0, 0, 0),
